import json
import pandas as pd

# Let's see what variables are actually available
print("Available variables in scope:")
for var_name in sorted(dir()):
    if not var_name.startswith('_'):
        print(var_name)

# Now let's check if the specific variables exist
print("\n" + "="*50)
if 'children_books' in dir():
    print("Found: children_books")
else:
    print("Not found: children_books")

if 'reviews_2020' in dir():
    print("Found: reviews_2020")
else:
    print("Not found: reviews_2020")

print("\nDone checking scope")

